**notification.hooks.ts**
```typescript
import { createContext, useContext, useState, useEffect } from 'react';
import { NotificationProps } from './notification.helpers';

const NotificationContext = createContext(null);

const useNotification = () => {
  const notificationElement = useContext(NotificationContext);
  const [isNotificationOpen, setIsNotificationOpen] = useState(false);

  useEffect(() => {
    if (notificationElement) {
      const closeNotification = async () => {
        await notificationElement.close();
        setIsNotificationOpen(false);
      };
      notificationElement.addEventListener('close', closeNotification);
      return () => {
        notificationElement.removeEventListener('close', closeNotification);
      };
    }
  }, [notificationElement]);

  const notify = async (props: NotificationProps) => {
    if (!notificationElement) return;

    const { heading, subheading, type } = props;
    await notificationElement.open({
      heading,
      subheading,
      type,
    });
    setIsNotificationOpen(true);
  };

  return { notify, isNotificationOpen };
};

export { useNotification, NotificationContext };
